// ---------------------------------------------------------------------------
// Style helpers
// ---------------------------------------------------------------------------

func proposalCardBorderClass(status string) string {
	switch status {
	case "pending":
		return "border-primary/30 bg-primary/5"
	case "approved":
		return "border-success/20 bg-success/5"
	case "deferred":
		return "border-warning/20 bg-warning/5"
	default: // expired, etc.
		return "border-base-content/10 bg-base-100 opacity-70"
	}
}

func proposalStatusBadgeClass(status string) string {
	switch status {
	case "pending":
		return "badge-primary"
	case "approved":
		return "badge-success"
	case "deferred":
		return "badge-warning"
	default:
		return "badge-ghost"
	}
}

func proposalStatusLabel(status string) string {
	switch status {
	case "pending":
		return "Pending"
	case "approved":
		return "Approved"
	case "deferred":
		return "Deferred"
	case "expired":
		return "Expired"
	default:
		return status
	}
}

func proposalTriggerBadgeClass(reason string) string {
	switch reason {
	case "signals":
		return "badge-error"
	case "evidence":
		return "badge-info"
	default: // time
		return "badge-ghost"
	}
}

func proposalTriggerIcon(reason string) string {
	switch reason {
	case "signals":
		return "lucide--radio"
	case "evidence":
		return "lucide--file-text"
	default:
		return "lucide--clock"
	}
}

func proposalTriggerLabel(reason string) string {
	switch reason {
	case "signals":
		return "Critical signals"
	case "evidence":
		return "New evidence"
	default:
		return "Scheduled"
	}
}

func proposalAge(t time.Time) string {
	d := time.Since(t)
	switch {
	case d < time.Minute:
		return "just now"
	case d < time.Hour:
		return fmt.Sprintf("%dm ago", int(d.Minutes()))
	case d < 24*time.Hour:
		return fmt.Sprintf("%dh ago", int(d.Hours()))
	default:
		return fmt.Sprintf("%dd ago", int(d.Hours()/24))
	}
}

